import React, { useState } from "react";
import "./UploadCV.css";

export default function UploadCV({ onResult, onLoading }) {
  const [mode, setMode] = useState("file");
  const [file, setFile] = useState(null);
  const [text, setText] = useState("");
  const [dragging, setDragging] = useState(false);
  const [error, setError] = useState("");

  const acceptFile = (f) => {
    if (f?.type === "application/pdf") { setFile(f); setError(""); }
    else { setError("Only PDF files are accepted."); setFile(null); }
  };

  const handleSubmit = async () => {
    setError("");
    onLoading(true);
    onResult(null);

    try {
      let res;
      if (mode === "file") {
        if (!file) { setError("Please select a PDF file."); onLoading(false); return; }
        const fd = new FormData();
        fd.append("file", file);
        res = await fetch("http://localhost:8000/predict/file", { method: "POST", body: fd });
      } else {
        if (!text.trim()) { setError("Please enter resume text."); onLoading(false); return; }
        res = await fetch("http://localhost:8000/predict/text", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ text }),
        });
      }

      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.detail || json.error || "Server error.");
      onResult(json.data);
    } catch (e) {
      setError(e.message);
    } finally {
      onLoading(false);
    }
  };

  return (
    <div className="upcv-root">

      {/* ── MODE TABS ── */}
      <div className="upcv-tabs">
        <button
          className={`upcv-tab ${mode === "file" ? "active" : ""}`}
          onClick={() => setMode("file")}
        >
          <i className="bi bi-file-earmark-pdf" />
          PDF Upload
        </button>
        <button
          className={`upcv-tab ${mode === "text" ? "active" : ""}`}
          onClick={() => setMode("text")}
        >
          <i className="bi bi-textarea-t" />
          Paste Text
        </button>
      </div>

      {/* ── FILE MODE ── */}
      {mode === "file" && (
        <div
          className={`drop-zone ${dragging ? "dz-over" : ""} ${file ? "dz-filled" : ""}`}
          onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
          onDragLeave={() => setDragging(false)}
          onDrop={(e) => { e.preventDefault(); setDragging(false); acceptFile(e.dataTransfer.files[0]); }}
          onClick={() => document.getElementById("cv-input").click()}
        >
          <input
            id="cv-input"
            type="file"
            accept=".pdf"
            hidden
            onChange={(e) => acceptFile(e.target.files[0])}
          />

          {file ? (
            <div className="dz-file-row">
              <div className="dz-file-icon">
                <i className="bi bi-file-earmark-pdf-fill" />
              </div>
              <div className="dz-file-info">
                <span className="dz-fname">{file.name}</span>
                <span className="dz-fmeta">
                  {(file.size / 1024).toFixed(0)} KB &nbsp;·&nbsp; PDF Document
                </span>
              </div>
              <button
                className="dz-remove"
                onClick={(e) => { e.stopPropagation(); setFile(null); }}
                title="Remove file"
              >
                <i className="bi bi-x-lg" />
              </button>
            </div>
          ) : (
            <div className="dz-placeholder">
              <div className="dz-ring">
                <i className="bi bi-cloud-arrow-up-fill" />
              </div>
              <p className="dz-primary">Drop your PDF here</p>
              <p className="dz-secondary">
                or&nbsp;<span className="dz-link">click to browse</span>
              </p>
              <div className="dz-format-chip">PDF only · Max 10 MB</div>
            </div>
          )}
        </div>
      )}

      {/* ── TEXT MODE ── */}
      {mode === "text" && (
        <div className="text-wrap">
          <textarea
            className="resume-ta"
            placeholder="Paste resume content here — skills, experience, education, job titles..."
            value={text}
            onChange={(e) => setText(e.target.value)}
            rows={10}
          />
          <div className="ta-footer">
            <span className="ta-char">{text.length.toLocaleString()} chars</span>
            {text.length > 0 && (
              <button className="ta-clear" onClick={() => setText("")}>
                Clear
              </button>
            )}
          </div>
        </div>
      )}

      {/* ── ERROR ── */}
      {error && (
        <div className="upcv-error">
          <i className="bi bi-exclamation-triangle-fill" />
          {error}
        </div>
      )}

      {/* ── SUBMIT ── */}
      <button className="analyze-btn" onClick={handleSubmit}>
        <i className="bi bi-cpu-fill" />
        <span>Run Analysis</span>
        <i className="bi bi-arrow-right-short ms-auto" style={{ fontSize: "1.1rem" }} />
      </button>
    </div>
  );
}
